Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "width": 590,
  "height": 530,
  "padding": 10,
  "autosize": "none",
  "background": "#0f172a",
  "data": [
    {"name": "dataset"},
    {
      "name": "pie",
      "values": [
        {"label": "Seg. Iniciales",     "colorVal": "#ef4444", "key": "Fricción - Segundos Iniciales"},
        {"label": "Antes del Mensaje", "colorVal": "#f97316", "key": "Fricción - Antes de completar el mensaje"},
        {"label": "Buzón de Voz",      "colorVal": "#eab308", "key": "Fricción - Buzón de Voz / Contestador"},
        {"label": "Otras Causas",      "colorVal": "#64748b", "key": "Fricción - Otras Causas"}
      ],
      "transform": [
        {"type": "formula", "as": "value", "expr": "datum.key == ''Fricción - Segundos Iniciales'' ? vSeg : datum.key == ''Fricción - Antes de completar el mensaje'' ? vAntes : datum.key == ''Fricción - Buzón de Voz / Contestador'' ? vBuzon : vOtras"},
        {"type": "pie", "field": "value"}
      ]
    }
  ],
  "signals": [
    {"name": "hasData", "update": "length(data(''dataset'')) > 0"},
    {"name": "vTotal", "update": "hasData ? data(''dataset'')[0][''Cortaron Comunicación''] : 0"},
    {"name": "vSeg",   "update": "hasData ? data(''dataset'')[0][''Fricción - Segundos Iniciales''] : 0"},
    {"name": "vAntes", "update": "hasData ? data(''dataset'')[0][''Fricción - Antes de completar el mensaje''] : 0"},
    {"name": "vBuzon", "update": "hasData ? data(''dataset'')[0][''Fricción - Buzón de Voz / Contestador''] : 0"},
    {"name": "vOtras", "update": "hasData ? data(''dataset'')[0][''Fricción - Otras Causas''] : 0"}
  ],
  "marks": [
    {"type": "text", "encode": {"update": {"x": {"value": 300}, "y": {"value": 26}, "align": {"value": "center"}, "fontSize": {"value": 18}, "fontWeight": {"value": "bold"}, "fill": {"value": "#e2e8f0"}, "text": {"value": "Desglose de Fricción"}}}},
    {"type": "text", "encode": {"update": {"x": {"value": 300}, "y": {"value": 46}, "align": {"value": "center"}, "fontSize": {"value": 12}, "fill": {"value": "#64748b"}, "text": {"signal": "''Total Cortaron Comunicación: '' + format(vTotal, '','')"}}}},
    {"type": "arc", "from": {"data": "pie"}, "encode": {
      "enter": {
        "x": {"value": 210}, "y": {"value": 270},
        "startAngle": {"field": "startAngle"}, "endAngle": {"field": "endAngle"},
        "innerRadius": {"value": 90}, "outerRadius": {"value": 160},
        "fill": {"field": "colorVal"}, "stroke": {"value": "#0f172a"}, "strokeWidth": {"value": 3},
        "tooltip": {"signal": "{''Motivo'': datum.label, ''Cantidad'': format(datum.value, '',''), ''Porcentaje'': format(datum.value / max(vTotal, 1), ''.1%'')}"}
      }
    }},
    {"type": "text", "encode": {"update": {"x": {"value": 210}, "y": {"value": 263}, "align": {"value": "center"}, "fontSize": {"value": 24}, "fontWeight": {"value": "bold"}, "fill": {"value": "#e2e8f0"}, "text": {"signal": "format(vTotal, '','')"}}}},
    {"type": "text", "encode": {"update": {"x": {"value": 210}, "y": {"value": 283}, "align": {"value": "center"}, "fontSize": {"value": 12}, "fill": {"value": "#94a3b8"}, "text": {"value": "Cortaron"}}}},
    {"type": "rect", "from": {"data": "pie"}, "encode": {"update": {"x": {"value": 400}, "y": {"signal": "160 + datum.index * 45"}, "width": {"value": 16}, "height": {"value": 16}, "cornerRadius": {"value": 3}, "fill": {"field": "colorVal"}}}},
    {"type": "text",  "from": {"data": "pie"}, "encode": {"update": {"x": {"value": 424}, "y": {"signal": "172 + datum.index * 45"}, "fontSize": {"value": 12}, "fontWeight": {"value": "bold"}, "fill": {"field": "colorVal"}, "text": {"signal": "datum.label"}}}},
    {"type": "text",  "from": {"data": "pie"}, "encode": {"update": {"x": {"value": 424}, "y": {"signal": "186 + datum.index * 45"}, "fontSize": {"value": 11}, "fill": {"value": "#94a3b8"}, "text": {"signal": "format(datum.value, '','') + ''  ('' + format(datum.value / max(vTotal, 1), ''.1%'') + '')''"}}}
  ]
}'
